// ============================================================
// Inference Functions
// ============================================================

static inline float sac_relu(float x) { return x > 0.0f ? x : 0.0f; }

static inline float sac_clamp(float x, float lo, float hi) {
  if (x < lo)
    return lo;
  if (x > hi)
    return hi;
  return x;
}

/*
 * Build the observation vector from raw sensor readings.
 * pend_pos: pendulum angle (rad, 0 = upright)
 * arm_pos:  arm angle (rad)
 * pend_vel: pendulum angular velocity (rad/s)
 * arm_vel:  arm angular velocity (rad/s)
 * last_voltage: voltage applied in previous step
 */
static void sac_build_obs(float obs[SAC_OBS_DIM], float pend_pos, float arm_pos,
                          float pend_vel, float arm_vel, float last_voltage) {
  obs[0] = cosf(pend_pos);
  obs[1] = sinf(pend_pos);
  obs[2] = cosf(arm_pos);
  obs[3] = sinf(arm_pos);
  obs[4] = pend_vel / VEL_NORM_PEND;
  obs[5] = arm_vel / VEL_NORM_ARM;
  obs[6] = sac_clamp(last_voltage / RL_VCAP, -1.0f, 1.0f);
}

/*
 * Run SAC actor forward pass.
 * Returns action in [-1, 1] (tanh-squashed).
 */
static float sac_forward(const float obs[SAC_OBS_DIM]) {
  float h0[256];
  for (int i = 0; i < 256; i++) {
    float sum = b_hidden_0[i];
    for (int j = 0; j < SAC_OBS_DIM; j++) {
      sum += w_hidden_0[i * SAC_OBS_DIM + j] * obs[j];
    }
    h0[i] = sac_relu(sum);
  }

  float h1[256];
  for (int i = 0; i < 256; i++) {
    float sum = b_hidden_1[i];
    for (int j = 0; j < 256; j++) {
      sum += w_hidden_1[i * 256 + j] * h0[j];
    }
    h1[i] = sac_relu(sum);
  }

  float mu = b_mu[0];
  for (int j = 0; j < 256; j++) {
    mu += w_mu[j] * h1[j];
  }

  return tanhf(mu);
}

/*
 * Apply motor deadzone compensation.
 */
static float sac_deadzone(float voltage) {
  if (voltage > DEADZONE_THRESH) {
    voltage += DEADZONE_VAL;
  } else if (voltage < -DEADZONE_THRESH) {
    voltage -= DEADZONE_VAL;
  } else {
    voltage = 0.0f;
  }
  return sac_clamp(voltage, -PROP_VCAP, PROP_VCAP);
}

/*
 * Proportional catch controller.
 */
static float proportional_voltage(float arm_pos, float arm_vel, float pend_pos,
                                  float pend_vel, float last_voltage) {
  float u = -(K1 * arm_pos + K2 * arm_vel + K3 * pend_pos + K4 * pend_vel +
              K5 * last_voltage);
  u = sac_clamp(u, -PROP_VCAP, PROP_VCAP);
  return sac_deadzone(u);
}

/*
 * Full control pipeline: sensor data -> voltage.
 * Call this every control loop iteration.
 *
 * Returns the voltage to apply to the motor.
 * Sets *controller to 0 for SAC, 1 for Proportional, 2 for FALLEN.
 */
static float sac_control_step(float pend_pos, float arm_pos, float pend_vel,
                              float arm_vel, float last_voltage,
                              int *controller) {

  // Wrap pend_pos to [-pi, pi]
  pend_pos = fmodf(pend_pos + (float)M_PI, 2.0f * (float)M_PI) - (float)M_PI;

  float abs_pend = fabsf(pend_pos);

  // Safety cutoff
  if (abs_pend > SAFE_ANGLE) {
    *controller = 2; // FALLEN
    return 0.0f;
  }

  float voltage;

  if (abs_pend < RL_ANGLE_RAD) {
    // SAC control
    *controller = 0;
    float obs[SAC_OBS_DIM];
    sac_build_obs(obs, pend_pos, arm_pos, pend_vel, arm_vel, last_voltage);
    float action = sac_forward(obs);
    voltage = action * RL_VCAP;
    voltage = sac_clamp(voltage, -RL_VOLTAGE_LIMIT, RL_VOLTAGE_LIMIT);
    voltage = sac_deadzone(voltage);
  } else {
    // Proportional catch
    *controller = 1;
    voltage = proportional_voltage(arm_pos, arm_vel, pend_pos, pend_vel,
                                   last_voltage);
  }

  return voltage;
}

